import React, { useEffect } from 'react';
import './App.css';
import { useNavigate } from 'react-router-dom';

const Modal = ({ isOpen, onClose }) => { 

    useEffect(() => {
        const modalOc = document.querySelector('.modal_1 > li:first-child');

        const clickHandler = () => {
            // navigate를 사용하여 페이지 이동
            navigate('/diarypage');
        };

        // 클릭 이벤트 리스너 추가
        if (modalOc) {
            modalOc.addEventListener('click', clickHandler);
        }

        // cleanup 함수로 컴포넌트가 unmount될 때 이벤트 리스너 제거
        return () => {
            if (modalOc) {
                modalOc.removeEventListener('click', clickHandler);
            }
        };
    }, [navigate]);  // 의존성 배열에 navigate 추가

    if (!isOpen) return null;  // isOpen이 false일 때 모달을 렌더링하지 않음

    return (
        <div className='modal'>
            <ul className='modal_1'>
               <li>
                    잘자요
               </li>
                <li>
                    애칭 설정
                </li>
                <li>
                    Diray List
                </li>
            </ul>
            <ul className='modal_2'>
                <li></li>
            </ul> 
        </div>
    );
}

export default Modal;
